"use strict";

function noopMiddleware() {
  return function multerShimMiddleware(req, _res, next) {
    if (!Array.isArray(req.files)) req.files = [];
    if (!req.file) req.file = null;
    next();
  };
}

function multer(_options = {}) {
  return {
    array() {
      return noopMiddleware();
    },
    single() {
      return noopMiddleware();
    },
    fields() {
      return noopMiddleware();
    },
    none() {
      return noopMiddleware();
    },
    any() {
      return noopMiddleware();
    },
  };
}

multer.diskStorage = function diskStorage(options = {}) {
  return {
    _multerShim: true,
    destination: options.destination,
    filename: options.filename,
  };
};

multer.memoryStorage = function memoryStorage() {
  return { _multerShim: true, memory: true };
};

module.exports = multer;
